// Code node: "Prepare Message"
// Place this after the Webhook and text extraction, before the AI Agent
var webhookBody = "";
try {
  webhookBody = $('Webhook').item.json.body.payload.body || "";
} catch(e) {}
if (!webhookBody) webhookBody = "I sent an image";
var ocrText = "";
try {
  ocrText = $('Extracting text from images').item.json.responses[0].textAnnotations[0].description || "";
} catch(e) {}
var userMessage = webhookBody;
if (ocrText) {
  userMessage += "\n\n[Text extracted from the image I sent:]\n" + ocrText;
}
return { json: { userMessage: userMessage } };

var rawData = $input.item.json;
// n8n AI Agent sends data as some_input (JSON string) - needs parsing
var parsed = null;
if (rawData.some_input) {
  try { parsed = JSON.parse(rawData.some_input); } catch(e) {}
}
var API_TOKEN = rawData.api_token || (parsed && parsed.api_token) || "";
var action = (parsed && parsed.action) || rawData.action;
var params = (parsed && parsed.params) || rawData.params || {};
var BASE_URL = "https://api.rivhit.co.il/online/RivhitOnlineAPI.svc";

var url = "";
var body = {};

// Parse document number: "01/003619" → 3619, " 3619" → 3619
function parseDocNum(val) {
  if (val === undefined || val === null) return val;
  var s = String(val);
  if (s.indexOf("/") !== -1) s = s.split("/").pop();
  var n = parseInt(s);
  return isNaN(n) ? val : n;
}

// Convert value to integer (remove non-numeric characters like dashes)
function toInt(val) {
  if (val === undefined || val === null) return val;
  var n = parseInt(String(val).replace(/\D/g, ''));
  return isNaN(n) ? val : n;
}

// Convert date: "08022026" → "08/02/2026", already correct format? return as-is
function formatDate(val) {
  if (!val) return val;
  var s = String(val);
  if (s.indexOf("/") !== -1 || s.indexOf("-") !== -1) return s;
  if (s.length === 8) return s.substring(0,2) + "/" + s.substring(2,4) + "/" + s.substring(4);
  return s;
}

// Hide api_token from body before printing in errors
function safeBody(b) {
  var copy = {};
  for (var k in b) {
    if (k === "api_token") {
      copy[k] = "***";
    } else {
      copy[k] = b[k];
    }
  }
  return JSON.stringify(copy);
}

// Build payment object for bank transfer
function buildTransferPayment(p) {
  var pay = { payment_type: 9, amount_nis: p.amount };
  if (p.bank_code) pay.bank_code = toInt(p.bank_code);
  if (p.branch_number) pay.branch_number = toInt(p.branch_number);
  if (p.bank_account_number) pay.bank_account_number = toInt(p.bank_account_number);
  if (p.due_date) pay.due_date = formatDate(p.due_date);
  return pay;
}

// Build payment object for check
function buildCheckPayment(p) {
  var pay = {
    payment_type: 1,
    amount_nis: p.amount,
    bank_code: toInt(p.bank_code),
    branch_number: toInt(p.branch_number),
    bank_account_number: toInt(p.bank_account_number),
    check_number: toInt(p.check_number)
  };
  if (p.due_date) pay.due_date = formatDate(p.due_date);
  return pay;
}

// Build payment object for credit card
function buildCreditPayment(p) {
  var pay = { payment_type: 4, amount_nis: p.amount };
  if (p.number_of_payments) pay.number_of_payments = toInt(p.number_of_payments);
  if (p.credit_type) pay.credit_type = toInt(p.credit_type);
  if (p.card_number) pay.card_number = String(p.card_number);
  if (p.voucher_number) pay.voucher_number = String(p.voucher_number);
  return pay;
}

// Check credit card detail completeness - returns warning if fields are missing
function creditWarning(p) {
  var missing = [];
  if (!p.card_number) missing.push("card_number (last 4 digits)");
  if (!p.voucher_number) missing.push("voucher_number (reference/voucher)");
  if (missing.length > 0) return " | ⚠️ Missing in receipt: " + missing.join(", ") + " - ask the customer!";
  return "";
}

// === Receipts ===

if (action === "create_receipt_cash") {
  url = BASE_URL + "/Receipt.New";
  body = {
    api_token: API_TOKEN,
    receipt_type: 1,
    customer_id: params.customer_id || 0,
    payments: [{ payment_type: 2, amount_nis: params.amount }]
  };

} else if (action === "create_receipt_check") {
  url = BASE_URL + "/Receipt.New";
  body = {
    api_token: API_TOKEN,
    receipt_type: 1,
    customer_id: params.customer_id || 0,
    payments: [buildCheckPayment(params)]
  };

} else if (action === "create_receipt_credit") {
  url = BASE_URL + "/Receipt.New";
  body = {
    api_token: API_TOKEN,
    receipt_type: 1,
    customer_id: params.customer_id || 0,
    payments: [buildCreditPayment(params)]
  };

} else if (action === "create_receipt_transfer") {
  url = BASE_URL + "/Receipt.New";
  body = {
    api_token: API_TOKEN,
    receipt_type: 1,
    customer_id: params.customer_id || 0,
    payments: [buildTransferPayment(params)]
  };

} else if (action === "create_receipt_multiple") {
  url = BASE_URL + "/Receipt.New";
  var payArr = [];
  for (var i = 0; i < params.payments.length; i++) {
    var p = params.payments[i];
    if (p.type === "cash") {
      payArr.push({ payment_type: 2, amount_nis: p.amount });
    } else if (p.type === "check") {
      payArr.push(buildCheckPayment(p));
    } else if (p.type === "credit") {
      payArr.push(buildCreditPayment(p));
    } else if (p.type === "transfer") {
      payArr.push(buildTransferPayment(p));
    }
  }
  body = {
    api_token: API_TOKEN,
    receipt_type: 1,
    customer_id: params.customer_id || 0,
    payments: payArr
  };

} else if (action === "create_receipt_refund") {
  url = BASE_URL + "/Receipt.New";
  body = {
    api_token: API_TOKEN,
    receipt_type: 3,
    customer_id: params.customer_id || 0,
    payments: [{ payment_type: 2, amount_nis: params.amount }]
  };

// === Closing/Cancelling Documents ===

} else if (action === "close_invoice") {
  url = BASE_URL + "/Document.Close";
  body = {
    api_token: API_TOKEN,
    document_type: params.document_type || 1,
    document_number: parseDocNum(params.document_number),
    closing_type: params.closing_type || 1,
    closing_number: parseDocNum(params.closing_number),
    closing_date: formatDate(params.closing_date),
    amount_close: params.amount_close,
    document_is_receipt: false
  };

} else if (action === "reopen_document") {
  url = BASE_URL + "/Document.Reopen";
  body = {
    api_token: API_TOKEN,
    document_type: params.document_type || 1,
    document_number: parseDocNum(params.document_number)
  };

} else if (action === "cancel_receipt") {
  url = BASE_URL + "/Receipt.Cancel";
  body = {
    api_token: API_TOKEN,
    receipt_type: params.receipt_type || 1,
    receipt_number: params.receipt_number
  };
  if (params.comments) body.comments = params.comments;
  if (params.email) body.email_to = params.email;
  if (params.cancellation_date) body.cancellation_date = formatDate(params.cancellation_date);

} else if (action === "cancel_document") {
  url = BASE_URL + "/Document.Cancel";
  body = {
    api_token: API_TOKEN,
    document_type: params.document_type || 1,
    document_number: parseDocNum(params.document_number)
  };
  if (params.comments) body.comments = params.comments;
  if (params.email) body.email_to = params.email;
  if (params.cancellation_date) body.cancellation_date = formatDate(params.cancellation_date);

// === Search & Document Details ===

} else if (action === "search_receipt") {
  url = BASE_URL + "/Receipt.List";
  body = { api_token: API_TOKEN };
  if (params.from_date) body.from_date = params.from_date;
  if (params.to_date) body.to_date = params.to_date;
  if (params.customer_id) {
    body.from_customer_id = params.customer_id;
    body.to_customer_id = params.customer_id;
  }

} else if (action === "get_receipt_details") {
  url = BASE_URL + "/Receipt.Details";
  body = {
    api_token: API_TOKEN,
    receipt_type: params.receipt_type || 1,
    receipt_number: params.receipt_number
  };

} else if (action === "search_invoice") {
  url = BASE_URL + "/Document.List";
  body = {
    api_token: API_TOKEN,
    from_document_type: 1,
    to_document_type: 1,
    from_date: params.from_date,
    to_date: params.to_date
  };
  if (params.customer_id) {
    body.from_customer_id = params.customer_id;
    body.to_customer_id = params.customer_id;
  }

} else if (action === "get_document_details") {
  url = BASE_URL + "/Document.Details";
  body = {
    api_token: API_TOKEN,
    document_type: params.document_type || 1,
    document_number: parseDocNum(params.document_number)
  };

// === Sending Documents by Email ===

} else if (action === "send_receipt") {
  url = BASE_URL + "/Receipt.Send";
  body = {
    api_token: API_TOKEN,
    receipt_type: params.receipt_type || 1,
    receipt_number: params.receipt_number,
    email: params.email
  };

} else if (action === "send_document") {
  url = BASE_URL + "/Document.Send";
  body = {
    api_token: API_TOKEN,
    document_type: params.document_type || 1,
    document_number: parseDocNum(params.document_number),
    email: params.email
  };

// === Documents ===

} else if (action === "create_invoice_receipt") {
  url = BASE_URL + "/Document.New";
  body = {
    api_token: API_TOKEN,
    document_type: 2,
    customer_id: params.customer_id || 0,
    price_include_vat: true,
    items: params.items,
    payments: params.payments
  };
  if (params.comments) body.comments = params.comments;

} else if (action === "create_invoice_receipt_extended") {
  url = BASE_URL + "/Document.NewExtended";
  body = {
    api_token: API_TOKEN,
    document_type: params.document_type || 2,
    receipt_type: params.receipt_type || 1,
    customer_id: params.customer_id || 0,
    price_include_vat: true,
    items: params.items,
    payments: params.payments
  };
  if (params.comments) body.comments = params.comments;

} else if (action === "create_credit_note") {
  url = BASE_URL + "/Document.New";
  var creditItems = [];
  for (var ci = 0; ci < params.items.length; ci++) {
    var item = {};
    for (var ck in params.items[ci]) item[ck] = params.items[ci][ck];
    if (item.price_nis > 0) item.price_nis = -item.price_nis;
    creditItems.push(item);
  }
  body = {
    api_token: API_TOKEN,
    document_type: 3,
    customer_id: params.customer_id || 0,
    price_include_vat: true,
    items: creditItems
  };
  if (params.original_document_number) {
    body.closed_document_type = params.original_document_type || 1;
    body.closed_document_number = parseDocNum(params.original_document_number);
  }
  if (params.comments) body.comments = params.comments;

// === Customers ===

} else if (action === "get_customer") {
  url = BASE_URL + "/Customer.Get";
  body = { api_token: API_TOKEN };
  if (params.customer_id) body.customer_id = params.customer_id;
  if (params.email) body.email = params.email;
  if (params.acc_ref) body.acc_ref = params.acc_ref;

} else if (action === "get_balance") {
  url = BASE_URL + "/Customer.Balance";
  body = {
    api_token: API_TOKEN,
    customer_id: params.customer_id
  };

} else if (action === "search_customer") {
  url = BASE_URL + "/Customer.List";
  body = { api_token: API_TOKEN };
  if (params.customer_type) body.customer_type = params.customer_type;

} else if (action === "create_customer") {
  url = BASE_URL + "/Customer.New";
  body = {
    api_token: API_TOKEN,
    last_name: params.last_name
  };
  if (params.first_name) body.first_name = params.first_name;
  if (params.phone) body.phone = params.phone;
  if (params.email) body.email = params.email;
  if (params.address) body.address = params.address;
  if (params.city) body.city = params.city;
  if (params.id_number) body.id_number = params.id_number;
  if (params.vat_number) body.vat_number = params.vat_number;

} else if (action === "update_customer") {
  url = BASE_URL + "/Customer.Update";
  body = {
    api_token: API_TOKEN,
    customer_id: params.customer_id
  };
  if (params.last_name) body.last_name = params.last_name;
  if (params.first_name) body.first_name = params.first_name;
  if (params.phone) body.phone = params.phone;
  if (params.email) body.email = params.email;
  if (params.address) body.address = params.address;
  if (params.city) body.city = params.city;
  if (params.zipcode) body.zipcode = params.zipcode;

// === General Information ===

} else if (action === "get_banks") {
  url = BASE_URL + "/Payment.BankList";
  body = { api_token: API_TOKEN };

} else if (action === "get_vat_rate") {
  url = BASE_URL + "/Accounting.VatRate";
  body = { api_token: API_TOKEN };

} else {
  return "Unrecognized action: " + action + " | raw keys: " + Object.keys(rawData).join(",") + " | some_input exists: " + !!rawData.some_input;
}

// Add comments from agent (for all receipt and document types)
if (params.comments && action.indexOf("create_receipt") === 0 && !body.comments) {
  body.comments = params.comments;
}

// Add bank transfer reference_number to comments
if (params.reference_number && action.indexOf("create_receipt") === 0) {
  var refComment = "Transfer reference: " + params.reference_number;
  body.comments = body.comments ? (body.comments + " | " + refComment) : refComment;
}

// Add reference and automatic comment with invoice number
if (params.document_number && (action.indexOf("create_receipt") === 0)) {
  var refNum = parseDocNum(params.document_number);
  if (typeof refNum === "number") body.reference = refNum;
  var autoComment = "Against tax invoice number " + params.document_number;
  body.comments = body.comments ? (body.comments + " | " + autoComment) : autoComment;
}

// Automatic customer lookup by tax ID or email
if (action.indexOf("create_receipt") === 0 || action.indexOf("create_invoice") === 0 || action === "create_credit_note") {
  if (params.find_by_id) {
    body.find_by_id = true;
    body.create_customer = true;
  }
  if (params.find_by_mail) body.find_by_mail = true;
  if (params.create_customer) body.create_customer = true;
  var idVal = params.id_number || params.vat_number;
  if (idVal) {
    body.id_number = idVal;
    body.vat_number = idVal;
  }
  if (params.last_name) body.last_name = params.last_name;
  if (params.first_name) body.first_name = params.first_name;
  if (params.phone) body.phone = params.phone;
  if (params.email) {
    body.email_to = params.email;
    body.send_mail = true;
  }
}

try {
  var result = await this.helpers.httpRequest({
    method: "POST",
    url: url,
    headers: {
      "Content-Type": "application/json",
      "Accept": "application/json"
    },
    body: body,
    json: true
  });
  var resultStr = JSON.stringify(result);
  if (action === "create_receipt_credit") {
    resultStr += creditWarning(params);
  }
  if (action === "create_receipt_multiple" && params.payments) {
    for (var wi = 0; wi < params.payments.length; wi++) {
      if (params.payments[wi].type === "credit") {
        resultStr += creditWarning(params.payments[wi]);
        break;
      }
    }
  }
  return resultStr;
} catch (e) {
  var errInfo = "API Error: " + e.message;
  errInfo += " | sent body: " + safeBody(body);
  try {
    if (e.cause && e.cause.response && e.cause.response.body) {
      errInfo += " | server response: " + JSON.stringify(e.cause.response.body);
    } else if (e.response && e.response.body) {
      errInfo += " | server response: " + JSON.stringify(e.response.body);
    } else if (e.body) {
      errInfo += " | server response: " + JSON.stringify(e.body);
    } else if (e.data) {
      errInfo += " | server response: " + JSON.stringify(e.data);
    }
  } catch(x) {}
  try { errInfo += " | error keys: " + Object.keys(e).join(","); } catch(x) {}
  return errInfo;
}

const output = $input.first().json.output;
const parsed = JSON.parse(output);

return [{ json: parsed }];
